sql:
SELECT is_public, COUNT(*) AS avatar_count
FROM avatars
GROUP BY is_public;

SELECT user_id, COUNT(*) AS reset_count
FROM password_resets
GROUP BY user_id;

SELECT username, email, phone_number
FROM users
WHERE confirmed = 1 AND is_locked = 1 AND failed_login_attempts > 0;

SELECT COUNT(*)
FROM users
WHERE users.confirmed = 1 AND users.is_locked = 1;

SELECT user_id 
FROM email_confirmations 
WHERE is_confirmed = 0 AND expiration < CURRENT_TIMESTAMP;

SELECT COUNT(*) AS public_non_default_avatar_count
FROM avatars
WHERE is_public = 1 AND is_default = 0;

SELECT COUNT(*)
FROM email_confirmations
WHERE is_confirmed = 1;

external_knowledge:
confirmed = 1 refers to the users who have verified their email addresses; 
'pioneers' refers to the users who have verified their identities and are ranked based on their usernames; 
'top 5 pioneers' refers to the users with the first 5 ranks; 
'avatar identities' refers to the hashed file names for the users' avatar images.
